import urllib.request
import json
import time

def check_health(url, timeout=5):
    start = time.time()
    try:
        req = urllib.request.Request(url, method='GET')
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            elapsed = (time.time() - start) * 1000
            return {'status': 'UP', 'code': resp.status, 'latency_ms': round(elapsed, 1)}
    except Exception as e:
        elapsed = (time.time() - start) * 1000
        return {'status': 'DOWN', 'error': str(e)[:100], 'latency_ms': round(elapsed, 1)}

endpoints = [
    'https://httpbin.org/get',
    'https://api.github.com',
]
for url in endpoints:
    result = check_health(url)
    status = 'UP' if result['status'] == 'UP' else 'DOWN'
    print(f'  [{status}] {url} — {result.get("code", "N/A")} ({result["latency_ms"]}ms)')

