import os
import time
import hashlib

def get_file_hash(path):
    with open(path, 'rb') as f:
        return hashlib.md5(f.read()).hexdigest()

def watch_directory(path, interval=1, max_checks=5):
    state = {}
    for f in os.listdir(path):
        full = os.path.join(path, f)
        if os.path.isfile(full):
            state[f] = os.path.getmtime(full)

    print(f'Watching {path} ({len(state)} files)')
    for check in range(max_checks):
        time.sleep(interval)
        current = {}
        for f in os.listdir(path):
            full = os.path.join(path, f)
            if os.path.isfile(full):
                current[f] = os.path.getmtime(full)

        for f in current:
            if f not in state:
                print(f'  [NEW] {f}')
            elif current[f] != state[f]:
                print(f'  [MOD] {f}')
        for f in state:
            if f not in current:
                print(f'  [DEL] {f}')
        state = current
    print('Watch complete')

import tempfile
watch_directory(tempfile.gettempdir(), interval=0.1, max_checks=2)

