import os
import subprocess
import platform

def get_processes():
    if platform.system() == 'Darwin':
        result = subprocess.run(['ps', 'aux'], capture_output=True, text=True)
    else:
        result = subprocess.run(['ps', 'aux'], capture_output=True, text=True)

    processes = []
    for line in result.stdout.strip().split('\n')[1:]:
        parts = line.split(None, 10)
        if len(parts) >= 11:
            processes.append({
                'user': parts[0], 'pid': int(parts[1]),
                'cpu': float(parts[2]), 'mem': float(parts[3]),
                'command': parts[10][:60],
            })
    return processes

procs = get_processes()
print(f'Total processes: {len(procs)}')

# Top 5 by CPU
print('\nTop 5 by CPU:')
for p in sorted(procs, key=lambda x: x['cpu'], reverse=True)[:5]:
    print(f'  PID {p["pid"]:6d} CPU={p["cpu"]:5.1f}% MEM={p["mem"]:5.1f}% {p["command"]}')

# Top 5 by memory
print('\nTop 5 by Memory:')
for p in sorted(procs, key=lambda x: x['mem'], reverse=True)[:5]:
    print(f'  PID {p["pid"]:6d} CPU={p["cpu"]:5.1f}% MEM={p["mem"]:5.1f}% {p["command"]}')

