import ssl
import socket
import datetime

def check_ssl_cert(hostname, port=443):
    context = ssl.create_default_context()
    try:
        with socket.create_connection((hostname, port), timeout=5) as sock:
            with context.wrap_socket(sock, server_hostname=hostname) as ssock:
                cert = ssock.getpeercert()
                not_after = datetime.datetime.strptime(cert['notAfter'], '%b %d %H:%M:%S %Y %Z')
                days_left = (not_after - datetime.datetime.utcnow()).days
                return {
                    'hostname': hostname,
                    'issuer': dict(x[0] for x in cert['issuer']).get('organizationName', 'Unknown'),
                    'expires': cert['notAfter'],
                    'days_left': days_left,
                    'valid': days_left > 0,
                }
    except Exception as e:
        return {'hostname': hostname, 'error': str(e)[:100]}

domains = ['github.com', 'google.com']
for domain in domains:
    result = check_ssl_cert(domain)
    if 'error' in result:
        print(f'  {domain}: ERROR — {result["error"]}')
    else:
        status = 'VALID' if result['valid'] else 'EXPIRED'
        print(f'  {domain}: [{status}] expires {result["expires"]} ({result["days_left"]}d left)')
